#!/usr/bin/env node
// vendor/support-claude-sitemap/organize.mjs
//
// Deterministic post-crawl organizer. Reads collections.yaml and distributes the
// flat-mirrored article `.md` files into per-collection subdirectories named to
// match canonical URL topology (<collection-id>-<collection-slug>/), then renders
// a generated `_collection.md` index per collection (the support site has no `.md`
// for collection pages, and the article set changes daily).
//
// No network. Pure filesystem over already-fetched `.md`. The crawl
// (npm run crawl:vendor -- support-claude-sitemap) fetches the flat mirror; its
// collection-page parse emits the collection→article map this script consumes.
//
// Usage:
//   node organize.mjs                                   # scaffold: dirs + _collection.md (articles pending)
//   node organize.mjs --articles <flat-dir> --map map.json   # distribute fetched .md into subdirs
//
//   map.json shape: { "<collection-id>": ["<article-id>-<slug>", ...], ... }
//
// @cite vendor/support-claude-sitemap/collections.yaml
// @cite scripts/lib/url-to-path.ts   (topology naming)

import { readFileSync, writeFileSync, mkdirSync, existsSync, copyFileSync, readdirSync } from "node:fs";
import { dirname, resolve, join } from "node:path";
import { fileURLToPath } from "node:url";
import { parse as parseYaml } from "yaml";

const HERE = dirname(fileURLToPath(import.meta.url));
const argv = process.argv.slice(2);
const opt = (flag) => { const i = argv.indexOf(flag); return i >= 0 ? argv[i + 1] : undefined; };
const articlesDir = opt("--articles");
const mapPath = opt("--map");

const inv = parseYaml(readFileSync(join(HERE, "collections.yaml"), "utf8"));
const map = mapPath ? JSON.parse(readFileSync(mapPath, "utf8")) : {};

const manifest = { generated_at: new Date().toISOString(), source: "organize.mjs", collections: [] };

for (const c of inv.collections) {
  const dir = join(HERE, c.subdir);
  mkdirSync(dir, { recursive: true });

  // Distribute fetched article .md into this collection's subdir (deterministic order).
  const articleIds = [...(map[c.id] ?? [])].sort();
  const placed = [];
  for (const aid of articleIds) {
    const file = `${aid}.md`;
    if (articlesDir && existsSync(join(articlesDir, file))) {
      copyFileSync(join(articlesDir, file), join(dir, file));
    }
    if (existsSync(join(dir, file))) placed.push(file);
  }
  // If no map was supplied, surface whatever .md already sits in the subdir.
  const present = placed.length
    ? placed
    : readdirSync(dir).filter((f) => f.endsWith(".md") && f !== "_collection.md").sort();

  const lines = [
    `# ${c.title}`,
    ``,
    `- collection: \`${c.subdir}\``,
    `- source: ${c.url} (operator HTML — no \`.md\` variant)`,
    `- articles: ${c.last_articles_count} (as of ${inv.counts_as_of})`,
    `- last_crawled: ${c.last_crawled ?? "null"}`,
    ``,
    `## articles`,
    ``,
    present.length
      ? present.map((f) => `- [${f.replace(/\.md$/, "")}](${f})`).join("\n")
      : `_pending first crawl — run \`npm run crawl:vendor -- support-claude-sitemap\`, then re-run this organizer._`,
    ``,
  ].join("\n");
  writeFileSync(join(dir, "_collection.md"), lines);
  manifest.collections.push({ subdir: c.subdir, expected: c.last_articles_count, present: present.length });
}

writeFileSync(join(HERE, "manifest.yaml"),
  `# generated by organize.mjs — do not hand-edit\ngenerated_at: ${manifest.generated_at}\ncollections:\n` +
  manifest.collections.map((m) => `  - subdir: ${m.subdir}\n    expected: ${m.expected}\n    present: ${m.present}`).join("\n") + "\n");

const total = manifest.collections.reduce((n, m) => n + m.present, 0);
console.log(JSON.stringify({ ok: true, collections: manifest.collections.length, articles_present: total }, null, 2));
